{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires distinguishing between the optical transition energy (photon energy) and the binding energy relative to the band edge, then applying the Rydberg scaling law.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Determine the exciton binding energy (E_b) for the n=1 state. Calculate this by finding the difference between the band gap energy (E_g) and the observed 1s exciton peak energy (E_photon). Explicitly define whether the binding energy is treated as a positive magnitude or a negative energy shift relative to the conduction band edge."
    },
    {
      "label": "helper_2",
      "instructions": "Using the n=1 binding energy found in the previous step, calculate the binding energy for the n=3 state using the Rydberg formula for hydrogenic excitons, where E_n = E_b / n^2. Provide the final value as the energy required to dissociate the exciton, ensuring the sign convention matches the requirement for Rydberg energy (typically expressed as a positive magnitude of the binding energy)."
    }
  ],
  "synthesis_brief": "Combine the n=1 binding energy magnitude with the n=3 scaling factor to provide the final numerical value for the n=3 Rydberg energy."
}

